ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_ANBRUCH" CHECK (ANBRUCH in ('T', 'F', 'A', 'V', 'I', 'B')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_BESTELLER" CHECK (BESTELLER in ('LVS', 'HOST',  'BDE', 'ISI','WAWI')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_FREIGABE" CHECK (FREIGABE IN ('M', 'A', 'E')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_MENGE_BASIS" CHECK (MENGE_BASIS in ('LKE','LHM', 'LTE')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_SATZART" CHECK (SATZART in ('BE', 'LI', 'MA',  'LA', 'LU', 'RL', 'RK', 'BK', 'LK', 'MAK', 'LAK', 'LNK')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_STATUS" CHECK (STATUS in ('N', 'E', 'V', 'F',  'X', 'Z', 'L', 'R', 'D', 'T','x')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_STRATEGIE" CHECK (STRATEGIE in ('FIFO', 'LIFO')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_VORGANG_TYP" CHECK (VORGANG_TYP in ('WEI', 'WAI', 'WEE', 'WAE', 'WUI', 'WUE', 'KWE', 'KWA')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_WARE_DISPT" CHECK (WARE_DISPONIERT in ('T', 'F')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "CHECK_ORDER_POS_WA_M_UBERLIEF" CHECK (WA_MENGE_UEBERLIEF in ('T',  'F', 'N', 'ULTE',
'ULHM',
'EX',
'OLTE',
'OLHM')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ORDER_POS" ADD CONSTRAINT "PK_ISI_ORDER_POS" PRIMARY KEY ("AUF_ID")
  USING INDEX  ENABLE;


